// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

contract PredictionLogger {
    struct Prediction {
        string ticker;
        string predictionHash;
        uint256 timestamp;
        address author;
    }

    // Mapping from predictionHash to Prediction record
    mapping(string => Prediction) public predictions;

    // Array to keep track of all hashes (optional, for history)
    string[] public allHashes;

    event NewPrediction(
        string indexed ticker,
        string predictionHash,
        uint256 timestamp,
        address author
    );

    function logPrediction(string memory _ticker, string memory _predictionHash) external {
        require(predictions[_predictionHash].timestamp == 0, "Prediction already exists");

        Prediction memory newPrediction = Prediction({
            ticker: _ticker,
            predictionHash: _predictionHash,
            timestamp: block.timestamp,
            author: msg.sender
        });

        predictions[_predictionHash] = newPrediction;
        allHashes.push(_predictionHash);

        emit NewPrediction(_ticker, _predictionHash, block.timestamp, msg.sender);
    }

    function verifyPrediction(string memory _predictionHash) external view returns (bool, uint256, address) {
        Prediction memory p = predictions[_predictionHash];
        if (p.timestamp == 0) {
            return (false, 0, address(0));
        }
        return (true, p.timestamp, p.author);
    }

    function getTotalPredictions() external view returns (uint256) {
        return allHashes.length;
    }
}

contracts/PremiumSubscription.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

contract PremiumSubscription {
    address public owner;

    struct Subscription {
        bool isActive;
        uint256 expiryTimestamp;
    }

    mapping(address => Subscription) public subscriptions;

    event SubscriptionActivated(address indexed user, uint256 expiryTimestamp);
    event PaymentVerified(address indexed user, string paymentId);

    modifier onlyOwner() {
        require(msg.sender == owner, "Not authorized");
        _;
    }

    constructor() {
        owner = msg.sender;
    }

    // The backend (admin) can grant subscription after verifying Razorpay payment
    function grantSubscription(address _user, uint256 _durationInDays, string calldata _paymentId) external onlyOwner {
        uint256 currentExpiry = subscriptions[_user].expiryTimestamp;
        uint256 startTime = currentExpiry > block.timestamp ? currentExpiry : block.timestamp;
        uint256 newExpiry = startTime + (_durationInDays * 1 days);

        subscriptions[_user] = Subscription({
            isActive: true,
            expiryTimestamp: newExpiry
        });

        emit PaymentVerified(_user, _paymentId);
        emit SubscriptionActivated(_user, newExpiry);
    }

    function isPremium(address _user) external view returns (bool) {
        return subscriptions[_user].isActive && subscriptions[_user].expiryTimestamp > block.timestamp;
    }

    function getExpiry(address _user) external view returns (uint256) {
        return subscriptions[_user].expiryTimestamp;
    }
}

